// // This module is designed to implement a 4-bit counter that counts down on the negative edge of a clock signal. It includes a synchronous reset input that sets the counter to 7 when asserted, and an enable signal that, when low, allows the counter to decrement.
module counter (
  input clk,
  input reset,
  input en,
  output reg [3:0] count
);

  always @(posedge clk) begin
    if (reset) count <= 4'b0;
    else if (en) count <= count + 1;
  end

endmodule
